namespace TD.WPF.Commands.Trades
{
    public partial class TradeDeleteCommand : AbstractCommand
    {
        protected readonly TradeListVM _viewModel;
        
        public TradeDeleteCommand(TradeListVM viewModel)
        {
            _viewModel = viewModel;
        }

        public override bool CanExecute(object? parameter)
        {
            var trade = _viewModel.SelectedTrade;
            if (trade is null)
                return false;

            if (trade.Id < 1)
                return false;


            var result = _viewModel.TradeRepository
                                   .CanDeleteAsync(trade.Id)
                                   .GetAwaiter()
                                   .GetResult();
            return result;
        }

        public override async void Execute(object? parameter)
        {
            var trade = _viewModel.SelectedTrade;
            if (trade is null)
                return;

            if (trade.Id < 1)
                return;

            var result = MessageBox.Show(
                MessageStrings.AreYouSureToDelete,
                CommonStrings.AppTitle,
                MessageBoxButton.YesNo,
                MessageBoxImage.Question);

            if (result != MessageBoxResult.Yes)
                return;

            bool deleted = await _viewModel.TradeRepository.DeleteAsync(trade.Id);
            if (!deleted)
                return;

            _viewModel.SelectedTrade = null;
            _viewModel.Trades.Remove(trade);
            await _viewModel.LoadTradesAsync();
        }
    }
}